import numpy as np

def verify_speculative_token(p_target, p_draft):
    ratio = p_target / p_draft if p_draft > 0 else 0.0
    return float(np.minimum(1.0, ratio))

def run_practice():
    assert verify_speculative_token(0.8, 0.4) == 1.0
    assert verify_speculative_token(0.2, 0.4) == 0.5
